import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a maximum buffer size
        int bufferSize = 10;

        // Copy user input into a buffer with proper bounds checking
        char[] buffer = new char[bufferSize];

        // Only copy up to the maximum size of the buffer
        int lengthToCopy = Math.min(userInput.length(), bufferSize);
        userInput.getChars(0, lengthToCopy, buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
